def butterfly(n):
    lines = []
    for i in range(1, n + 1):
        row = '*' * i + ' ' * (2 * (n - i)) + '*' * i
        lines.append(row)
    return '\n'.join(lines + lines[::-1])

if __name__ == "__main__":
    print(butterfly(3))
